```rust
fn suggestion_key(s: &ValueSuggestion) -> String {
    match s {
        ValueSuggestion::Enum(v) | ValueSuggestion::Const(v) => format!("value:{}", v),
        ValueSuggestion::Boolean => "B".to_string(),
        ValueSuggestion::Null => "N".to_string(),
