```rust
fn collect_values_from(
    root,
    schema,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth,
) {
    if depth > MAX_SCHEMA_DEPTH { return; }
    let schema = follow_ref(...);  // follow $ref

    // const
    if let Some(const_val) = schema.get("const") {
        push_unique(suggestions, seen, ValueSuggestion::Const(const_val.clone()));
        return; // const overrides type for this node
    }
    // enum
    if let Some(enum_vals) = schema.get("enum").and_then(as_array) {
        for val in enum_vals {
            push_unique(suggestions, seen, ValueSuggestion::Enum(val.clone()));
        }
        return; // enum overrides type
    }
    // type
    collect_type_suggestions(schema, suggestions, seen);

    // compositions
    for keyword in ["allOf", "oneOf", "anyOf"] {
        if let Some(arr) = schema.get(keyword).and_then(as_array) {
            for branch in arr {
                collect_values_from(root, branch, suggestions, seen, depth+1);
            }
        }
    }
    // if/then/else
    ...
}
```

