```rust
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // const fully constrains the value for this subschema.
    if let Some(const_val) = schema.get("const") {
        push_value_suggestion(suggestions, seen, ValueSuggestion::Const(const_val.clone()));
        return;
    }

    // enum fully constrains the value for this subschema.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            push_value_suggestion(suggestions, seen, ValueSuggestion::Enum(val.clone()));
        }
        return;
    }

    // type-based suggestions (handles nullable arrays like ["boolean", "null"]).
    collect_type_value_suggestions(schema, suggestions, seen);

    // Recurse into composition keywords.
    for keyword in ["allOf", "oneOf", "anyOf"] {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }

    // if/then/else: collect from then and else branches.
    for keyword in ["then", "else"] {
        if let Some(branch) = schema.get(keyword) {
            collect_values_from(root, branch, suggestions, seen, depth + 1);
        }
    }
}

fn collect_type_value_suggestions(
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
) {
    let Some(type_value) = schema.get("type") else { return };
    let types: Vec<&str> = match type_value {
        serde_json::Value::String(s) => vec![s.as_str()],
        serde_json::Value::Array(arr) => arr.iter().filter_map(|v| v.as_str()).collect(),
        _ => return,
    };
    for t in types {
        match t {
            "boolean" => push_value_suggestion(suggestions, seen, ValueSuggestion::Boolean),
            "null" => push_value_suggestion(suggestions, seen, ValueSuggestion::Null),
            _ => {}
        }
    }
}

fn push_value_suggestion(
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    suggestion: ValueSuggestion,
) {
    let key = value_suggestion_key(&suggestion);
    if seen.insert(key) {
        suggestions.push(suggestion);
    }
}

fn value_suggestion_key(suggestion: &ValueSuggestion) -> String {
    match suggestion {
        ValueSuggestion::Enum(v) | ValueSuggestion::Const(v) => {
            format!("value:{}", v)
        }
        ValueSuggestion::Boolean => "boolean".to_string(),
        ValueSuggestion::Null => "null".to_string(),
    }
}
```

