/// Format title and description from a schema node into a single string.
fn format_annotation(schema: &serde_json::Value) -> Option<String> {
    let title = schema.get("title").and_then(|v| v.as_str());
    let description = schema.get("description").and_then(|v| v.as_str());
    match (title, description) {
        (Some(t), Some(d)) => Some(format!("{t}: {d}")),
        (Some(t), None) => Some(t.to_string()),
        (None, Some(d)) => Some(d.to_string()),
        (None, None) => None,
    }
}

/// Extract a human-readable type string from a schema node.
///
/// Handles both single-string `type` values (`"string"`) and array/nullable
/// unions (`["string", "null"]`), joining multiple types with `" | "`.
/// Returns `None` when the node has no usable `type`.
fn extract_schema_type(schema: &serde_json::Value) -> Option<String> {
    let type_value = schema.get("type")?;
    let types: Vec<&str> = match type_value {
        serde_json::Value::String(s) => vec![s.as_str()],
        serde_json::Value::Array(arr) => arr.iter().filter_map(|v| v.as_str()).collect(),
        _ => return None,
    };
    if types.is_empty() {
        return None;
    }
    Some(types.join(" | "))
}

