/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `const`, `enum`, and `type` to generate value suggestions. Composition
/// keywords (`allOf`, `oneOf`, `anyOf`) and conditional branches (`then`,
/// `else`) are merged, nullable `type` arrays are supported, and duplicate
/// suggestions are removed.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Recursively collect value suggestions from a schema node, merging all
/// composition and conditional branches while deduplicating by value.
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // `const` fully constrains the value for this subschema.
    if let Some(const_val) = schema.get("const") {
        push_value_suggestion(suggestions, seen, ValueSuggestion::Const(const_val.clone()));
        return;
    }

    // `enum` fully constrains the value for this subschema.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            push_value_suggestion(suggestions, seen, ValueSuggestion::Enum(val.clone()));
        }
        return;
    }

    // Type-based suggestions (handles nullable arrays like ["boolean", "null"]).
    collect_type_value_suggestions(schema, suggestions, seen);

    // Recurse into composition branches.
    for keyword in ["allOf", "oneOf", "anyOf"] {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
