/// Collect boolean/null value suggestions from a schema's `type` keyword,
/// accepting either a single string or an array of types (nullable unions).
fn collect_type_value_suggestions(
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
) {
    let Some(type_value) = schema.get("type") else {
        return;
    };
    let types: Vec<&str> = match type_value {
        serde_json::Value::String(s) => vec![s.as_str()],
        serde_json::Value::Array(arr) => arr.iter().filter_map(|v| v.as_str()).collect(),
        _ => return,
    };
    for type_str in types {
        match type_str {
            "boolean" => push_value_suggestion(suggestions, seen, ValueSuggestion::Boolean),
            "null" => push_value_suggestion(suggestions, seen, ValueSuggestion::Null),
            _ => {}
        }
    }
}

/// Push a suggestion unless an equal value has already been collected.
fn push_value_suggestion(
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    suggestion: ValueSuggestion,
) {
    if seen.insert(value_suggestion_key(&suggestion)) {
        suggestions.push(suggestion);
    }
}

/// Stable dedup key for a `ValueSuggestion` based on its concrete value.
fn value_suggestion_key(suggestion: &ValueSuggestion) -> String {
    match suggestion {
        ValueSuggestion::Enum(v) | ValueSuggestion::Const(v) => format!("value:{v}"),
        ValueSuggestion::Boolean => "boolean".to_string(),
        ValueSuggestion::Null => "null".to_string(),
    }
}

