/// Return a snippet placeholder appropriate for the given JSON schema type.
///
/// `schema_type` may be a joined nullable union (e.g. `"string | null"`); the
/// first (primary) type drives the placeholder so nullable properties still get
/// a useful non-null template.
fn snippet_for_type(schema_type: Option<&str>) -> &'static str {
    let primary = schema_type
        .and_then(|t| t.split(" | ").next())
        .unwrap_or("");
    match primary {
        "string" => "\"$1\"",
        "number" | "integer" => "${1:0}",
        "boolean" => "${1:false}",
        "object" => "{$1}",
        "array" => "[$1]",
        "null" => "null",
        _ => "$0",
    }
}

