#[test]
fn collect_values_no_suggestions() {
    let schema = serde_json::json!({
        "properties": {
            "name": { "type": "string" }
        }
    });
    let values = collect_values(&schema, &[], "name");
    assert!(values.is_empty());
}

#[test]
fn collect_values_nullable_boolean_type_array() {
    let schema = serde_json::json!({
        "properties": {
            "flag": { "type": ["boolean", "null"] }
        }
    });
    let values = collect_values(&schema, &[], "flag");
    // boolean + null, deduplicated.
    assert_eq!(values.len(), 2);
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
}

#[test]
fn collect_values_nullable_string_suggests_null_only() {
    let schema = serde_json::json!({
        "properties": {
            "nickname": { "type": ["string", "null"] }
        }
    });
    let values = collect_values(&schema, &[], "nickname");
    // strings produce no value suggestions, but null should still appear.
    assert_eq!(values.len(), 1);
    assert!(matches!(&values[0], ValueSuggestion::Null));
}

#[test]
fn collect_values_anyof_enum_and_null() {
    let schema = serde_json::json!({
        "properties": {
            "status": {
                "anyOf": [
                    { "type": "string", "enum": ["active", "paused"] },
                    { "type": "null" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "status");
    assert_eq!(values.len(), 3);
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Enum(e) if e == "active")));
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Enum(e) if e == "paused")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
}

#[test]
fn collect_values_anyof_overlapping_enums_deduped() {
    let schema = serde_json::json!({
        "properties": {
            "priority": {
                "anyOf": [
                    { "enum": ["low", "high"] },
                    { "enum": ["low", "medium"] }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "priority");
    // "low" appears in both branches but must be suggested only once.
    let enums: Vec<String> = values
        .iter()
        .filter_map(|v| match v {
            ValueSuggestion::Enum(e) => Some(e.to_string()),
            _ => None,
        })
        .collect();
    assert_eq!(enums, vec!["low", "high", "medium"]);
}

#[test]
fn collect_values_oneof_merges_branches() {
    let schema = serde_json::json!({
        "properties": {
            "port": {
                "oneOf": [
                    { "const": 80 },
                    { "const": 443 }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "port");
    assert_eq!(values.len(), 2);
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Const(c) if c == 80)));
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Const(c) if c == 443)));
}

#[test]
fn collect_values_if_then_else_branches() {
    let schema = serde_json::json!({
        "properties": {
            "x": {
                "if": { "type": "string" },
                "then": { "const": "a" },
                "else": { "const": "b" }
            }
        }
    });
    let values = collect_values(&schema, &[], "x");
    assert_eq!(values.len(), 2);
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Const(c) if c == "a")));
    assert!(values
        .iter()
        .any(|v| matches!(v, ValueSuggestion::Const(c) if c == "b")));
}

