/// A required property inside a `oneOf` branch still sorts ahead of optional ones.
#[tokio::test]
async fn completion_oneof_required_property_sorts_first() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""shape": {}"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let inner_brace = content.rfind('{').unwrap();
    let cursor_col = (inner_brace + 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let radius = items.iter().find(|i| i["label"] == "radius").unwrap();
    assert_eq!(radius["sortText"].as_str().unwrap().chars().next(), Some('0'));
    let detail = radius["detail"].as_str().unwrap();
    assert!(detail.contains("required"), "got: {detail}");
}

/// A value suggestible both by a `type` and an overlapping `enum` branch must
/// not produce duplicate labels (true/false/null each appear once).
#[tokio::test]
async fn completion_no_duplicate_value_labels_across_kinds() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""enabled": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"enabled\": ").unwrap() + "\"enabled\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    // The boolean branch yields true/false and the enum branch yields
    // true/false/null; expect exactly three unique labels.
    assert_eq!(
        names,
        vec!["true".to_string(), "false".to_string(), "null".to_string()],
        "expected deduplicated value labels, got: {names:?}"
    );
}

